from collections import defaultdict
def a_list(N):
    freq = defaultdict(int)
    for n in range(1, N+1):
        for k in range(n):
            val = n + k*(n-1)
            if val <= N:
                freq[val] += 1
    return [freq[n] for n in range(1, N+1)]
